        "titolo_orig": "L’Iran manda in piazza i leader",
        "testo_it": "Il presidente iraniano Pezeshkian partecipa alle proteste di piazza contro gli attacchi subiti dal Paese.",
        "priorita": "Media",
        "id_gruppo": 1,
        "link": "https://ilmanifesto.it/liran-manda-in-piazza-i-leader",
        "orario": "00:07",
